import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
import glob
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist", "alpha": 2.0, "beta": 1.5}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    if 'outdoor' in pstr: return 'outdoor'
    return 'room'

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in neighs if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def get_edge_distance(a, b):
        return ((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2) ** 0.5

    def shortest_path_distance(start, goal):
        if start == goal:
            return 0.0
        pq = [(0.0, start)]
        dists = {start: 0.0}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                return d
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    heapq.heappush(pq, (new_d, neigh))
        return float('inf')

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        pq = [(0.0, start)]
        dists = {start: 0.0}
        prev = {start: None}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    prev[neigh] = curr
                    heapq.heappush(pq, (new_d, neigh))
        if goal not in prev:
            return None
        curr = goal
        while prev.get(curr) != start and prev.get(curr) is not None:
            curr = prev[curr]
        return curr

    alpha = model.get("alpha", 2.0)
    beta = model.get("beta", 1.0)
    best_score = -float('inf')
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = shortest_path_distance(current_pos, tcoord)
        if dist == float('inf') or dist <= 0.0:
            continue
        score = (util ** beta) / (dist ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        if best_n is not None:
            return best_n
        return neighbors[0] if neighbors else None

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        if best_n is not None:
            return best_n
        return neighbors[0] if neighbors else None

    for neigh_raw in neighbors:
        if coord_to_tuple(neigh_raw) == next_coord:
            return neigh_raw

    best_utility = -1.0
    best_n = None
    for neigh_raw in neighbors:
        ncoord = coord_to_tuple(neigh_raw)
        util = utilities.get(ncoord, 0.0)
        if util > best_utility:
            best_utility = util
            best_n = neigh_raw
    return best_n if best_n is not None else (neighbors[0] if neighbors else None)


def run_evaluation(data_path: str, checkpoint: str, output_path: str):
    model = load_model(checkpoint)
    data_path = Path(data_path)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    config_path = data_path / "eval_config.json"
    map_list = []
    if config_path.exists():
        with open(config_path, "r") as f:
            config = json.load(f)
        if "map_paths" in config and config["map_paths"]:
            for p in config["map_paths"]:
                full_p = data_path / p
                if full_p.exists():
                    map_list.append(full_p)
            if not map_list:
                for p in config["map_paths"]:
                    map_list.append(data_path / p)
    if not map_list:
        print("No eval_config.json or empty, using 3 training maps per type for local testing.")
        train_data_dir = Path("/data")
        for env_type in ["room", "tunnel", "outdoor"]:
            map_dir = train_data_dir / "maps_train" / env_type
            if map_dir.exists():
                maps = sorted(list(map_dir.glob("*.png")))[:3]
                map_list.extend(maps)
    if not map_list:
        print("No maps found.")
        return

    print(f"Evaluating on {len(map_list)} maps.")
    results = []
    per_type = defaultdict(lambda: {"explored": [], "dist": [], "success": []})
    total_success = 0
    total_explored = 0.0
    successful_distances = []
    for map_path in map_list:
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            env_type = get_env_type(map_path)
            done = False
            step = 0
            max_steps = 128
            while not done and step < max_steps:
                target = select_waypoint(obs, model)
                if target is None:
                    break
                obs, info = env.step(target)
                done = info.get("done", False)
                step += 1
            metrics = env.get_metrics()
            success = 1 if metrics.get("success", False) else 0
            explored_rate = metrics.get("explored_rate", 0.0)
            travel_distance = metrics.get("travel_distance", 0.0)
            if success:
                successful_distances.append(travel_distance)
            results.append({
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel_distance),
                "explored_rate": float(explored_rate)
            })
            per_type[env_type]["explored"].append(explored_rate)
            per_type[env_type]["dist"].append(travel_distance if success else 0.0)
            per_type[env_type]["success"].append(success)
            total_success += success
            total_explored += explored_rate
        except Exception as e:
            print(f"Error on {map_path}: {str(e)}")
            results.append({
                "map_path": str(map_path.name),
                "env_type": get_env_type(map_path),
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })

    n_episodes = len(results)
    success_rate = total_success / n_episodes if n_episodes > 0 else 0.0
    mean_explored = total_explored / n_episodes if n_episodes > 0 else 0.0
    mean_distance = np.mean(successful_distances) if successful_distances else 0.0

    if successful_distances:
        scores = [300.0 / d for d in successful_distances if d > 0]
        exploration_score = (len(scores) / n_episodes) * np.mean(scores) if scores else 0.0
    else:
        exploration_score = 0.0

    per_type_summary = {}
    for t, stats in per_type.items():
        n_t = len(stats["success"])
        if n_t > 0:
            s_rate = sum(stats["success"]) / n_t
            e_rate = np.mean(stats["explored"])
            succ_dists = [d for d, s in zip(stats["dist"], stats["success"]) if s == 1 and d > 0]
            d_mean = np.mean(succ_dists) if succ_dists else 0.0
            per_type_summary[t] = {
                "explored_rate": float(e_rate),
                "travel_distance": float(d_mean),
                "success_rate": float(s_rate)
            }

    output = {
        "explored_rate": float(mean_explored),
        "travel_distance": float(mean_distance),
        "success_rate": float(success_rate),
        "per_episode": results,
        "per_type": per_type_summary,
        "total_episodes": n_episodes
    }
    with open(output_path, "w") as f:
        json.dump(output, f, indent=2)

    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {mean_explored:.4f}, Avg dist: {mean_distance:.2f}")
    print(f"Proxy exploration_score: {exploration_score:.4f}")
    if n_episodes <= 20:
        print("Local test on train subset done.")


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, required=True)
    parser.add_argument("--checkpoint", type=str, required=True)
    parser.add_argument("--output", type=str, required=True)
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)

if __name__ == "__main__":
    main()
